I have created the three requested components in `src/components/` and updated the dashboard page to use them.

### 1. `src/components/AddBookmarkForm.tsx`
Handles adding new bookmarks with a loading state and error handling.
```tsx
'use client'

import { useState, useRef, useTransition } from 'react'
import { addBookmark } from '@/app/dashboard/actions'

export function AddBookmarkForm() {
  const [isPending, startTransition] = useTransition()
  const [error, setError] = useState<string | null>(null)
  const formRef = useRef<HTMLFormElement>(null)

  async function handleSubmit(formData: FormData) {
    setError(null)
    startTransition(async () => {
      const result = await addBookmark(formData)
      if (result?.error) {
        setError(result.error)
      } else {
        formRef.current?.reset()
      }
    })
  }

  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
      <form ref={formRef} action={handleSubmit} className="space-y-4">
        <div>
          <label htmlFor="title" className="block text-sm font-medium text-gray-700 mb-1">Title</label>
          <input type="text" name="title" id="title" required placeholder="e.g. My Favorite Blog" className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-violet-500 outline-none" />
        </div>
        <div>
          <label htmlFor="url" className="block text-sm font-medium text-gray-700 mb-1">URL</label>
          <input type="url" name="url" id="url" required placeholder="https://example.com" className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-violet-500 outline-none" />
        </div>
        <div className="flex items-center gap-2">
          <input type="checkbox" name="is_public" id="is_public" className="w-4 h-4 text-violet-600 rounded" />
          <label htmlFor="is_public" className="text-sm text-gray-600">Make public</label>
        </div>
        {error && <p className="text-sm text-red-600 bg-red-50 p-3 rounded-lg">{error}</p>}
        <button type="submit" disabled={isPending} className="w-full py-2 bg-violet-600 text-white font-semibold rounded-lg hover:bg-violet-700 disabled:opacity-50">
          {isPending ? 'Adding...' : 'Add Bookmark'}
        </button>
      </form>
    </div>
  )
}
```

### 2. `src/components/BookmarkList.tsx`
Renders the list of bookmarks or a placeholder if empty.
```tsx
'use client'

import { Bookmark } from '@/lib/types'
import { BookmarkCard } from './BookmarkCard'

export function BookmarkList({ bookmarks }: { bookmarks: Bookmark[] }) {
  if (bookmarks.length === 0) {
    return <div className="py-12 text-center text-gray-400">No bookmarks yet. Start by adding one above!</div>
  }

  return (
    <div className="space-y-4">
