```

### 3. `src/components/BookmarkCard.tsx`
Individual bookmark card with inline editing and deletion.
```tsx
'use client'

import { useState, useTransition } from 'react'
import { Bookmark } from '@/lib/types'
import { updateBookmark, deleteBookmark } from '@/app/dashboard/actions'

export function BookmarkCard({ bookmark }: { bookmark: Bookmark }) {
  const [isEditing, setIsEditing] = useState(false)
  const [isPending, startTransition] = useTransition()
  const [error, setError] = useState<string | null>(null)

  const handleUpdate = async (formData: FormData) => {
    startTransition(async () => {
      const res = await updateBookmark(bookmark.id, formData)
      if (res?.error) setError(res.error); else setIsEditing(false)
    })
  }

  const handleDelete = async () => {
    if (confirm('Delete this bookmark?')) {
      startTransition(async () => {
        const res = await deleteBookmark(bookmark.id)
        if (res?.error) alert(res.error)
      })
    }
  }

  if (isEditing) {
    return (
      <div className="bg-white p-4 rounded-lg border border-violet-200 shadow-sm">
        <form action={handleUpdate} className="space-y-3">
          <input type="text" name="title" defaultValue={bookmark.title} required className="w-full px-3 py-1.5 border rounded" />
          <input type="url" name="url" defaultValue={bookmark.url} required className="w-full px-3 py-1.5 border rounded" />
          <div className="flex justify-end gap-2">
            <button type="button" onClick={() => setIsEditing(false)} className="px-3 py-1 text-sm">Cancel</button>
            <button type="submit" disabled={isPending} className="px-3 py-1 bg-violet-600 text-white rounded">{isPending ? 'Saving...' : 'Save'}</button>
          </div>
        </form>
      </div>
    )
  }

  return (
    <div className="bg-white p-4 rounded-lg border border-gray-100 shadow-sm hover:border-gray-200 group flex justify-between items-start">
      <div className="min-w-0">
        <a href={bookmark.url} target="_blank" className="text-lg font-semibold text-gray-900 hover:text-violet-600 truncate block">{bookmark.title}</a>
        <p className="text-sm text-gray-500 truncate">{bookmark.url}</p>
        {bookmark.is_public && <span className="text-[10px] bg-green-100 text-green-700 px-2 py-0.5 rounded-full font-bold uppercase">Public</span>}
      </div>
      <div className="flex gap-1 opacity-0 group-hover:opacity-100">
        <button onClick={() => setIsEditing(true)} className="p-1.5 hover:text-violet-600">Edit</button>
        <button onClick={handleDelete} className="p-1.5 hover:text-red-600">Delete</button>
      </div>
    </div>
  )
}
```

All components use Tailwind CSS for styling and `useTransition` for smooth loading states during server action execution.
